import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"The Rundown AI — 2026-05-22","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-22","date":"2026-05-22T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-22-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-22-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-05/2026-05-22-the-rundown-ai.md"};function i(s,e,m,u,l,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-22" tabindex="-1">🗞️ The Rundown AI — 2026-05-22 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-22" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-22&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="openai-cracks-an-80-year-math-belief" tabindex="-1"><a href="https://www.therundown.ai/p/openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">OpenAI cracks an 80-year math belief</a> <a class="header-anchor" href="#openai-cracks-an-80-year-math-belief" aria-label="Permalink to &quot;[OpenAI cracks an 80-year math belief](https://www.therundown.ai/p/openai-cracks-an-80-year-math-belief)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-21</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://offers.hubspot.com/using-chatgpt-at-work?utm_medium=email-media-newsletter&amp;utm_source=the-rundown-ai&amp;utm_campaign=creator&amp;utm_content=paid&amp;utm_term=5-21-2026" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Sam Altman called it a &quot;kinda big milestone.&quot; That may be the rare case of a tech CEO underselling a headline.</p><p>A reasoning model just autonomously disproved an 80-year-old famous math theory, in what the company is calling a first for AI in the field. A capability, OpenAI says, that could soon result in original discoveries across biology, physics, engineering, and more.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>OpenAI cracks an 80-year math belief</p></li><li><p>Google&#39;s AI Co-Scientist heads to labs</p></li><li><p>Audit Claude’s context of you and your work</p></li><li><p>Emergence’s five-town AI alignment showdown</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai" tabindex="-1">OPENAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="🧮-openai-cracks-an-80-year-math-belief" tabindex="-1">🧮 <strong><a href="https://openai.com/index/model-disproves-discrete-geometry-conjecture/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">OpenAI cracks an 80-year math belief</a></strong> <a class="header-anchor" href="#🧮-openai-cracks-an-80-year-math-belief" aria-label="Permalink to &quot;🧮 **[OpenAI cracks an 80-year math belief](https://openai.com/index/model-disproves-discrete-geometry-conjecture/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> OpenAI just <a href="https://openai.com/index/model-disproves-discrete-geometry-conjecture/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">announced</a> that an internal general reasoning model disproved a long-held belief tied to Erdős’ famous 1946 unit distance problem, claiming to have accomplished a first for AI in novel math discovery.</p><p><strong>The details:</strong></p><ul><li><p>Erdős’ 1946 unit distance problem asks how many same-length links you can draw between dots, with a grid-based theory shaping the field for 80 years.</p></li><li><p>The proof draws on a different branch of maths (algebraic number theory) and was <a href="https://cdn.openai.com/pdf/74c24085-19b0-4534-9c90-465b8e29ad73/unit-distance-remarks.pdf?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">verified</a> by experts including Tim Gowers, Noga Alon, and Thomas Bloom.</p></li><li><p>The solution <a href="https://x.com/polynoamial/status/2057179104315670826?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">came</a> from an internal general-purpose model that is being released soon, not from a math-specific system like DeepMind&#39;s AlphaProof.</p></li><li><p>OAI previously <a href="https://techcrunch.com/2025/10/19/openais-embarrassing-math/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">walked back</a> a 2025 claim that GPT-5 solved 10 Erdős problems, which ended up being literature finds instead of discoveries.</p></li></ul><p><strong>Why it matters:</strong> OAI&#39;s Alex Wei <a href="https://x.com/alexwei_/status/2057182873208369485?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">put it</a> well: &quot;math is a leading indicator of what is to come.&quot; If a general-purpose model can autonomously disprove an 80-year-old argument with its own solution, that&#39;s the early look of &quot;Level 4&quot; AI — systems making original contributions across fields, not just speeding up existing work.</p><h6 id="together-with-hubspot" tabindex="-1">TOGETHER WITH HUBSPOT <a class="header-anchor" href="#together-with-hubspot" aria-label="Permalink to &quot;TOGETHER WITH HUBSPOT&quot;">​</a></h6><h4 id="🧠-100-chatgpt-prompts-to-revolutionize-your-workflow" tabindex="-1">🧠 <strong><a href="https://offers.hubspot.com/using-chatgpt-at-work?utm_medium=email-media-newsletter&amp;utm_source=the-rundown-ai&amp;utm_campaign=creator&amp;utm_content=paid&amp;utm_term=5-21-2026" target="_blank" rel="noreferrer">100+ ChatGPT prompts to revolutionize your workflow</a></strong> <a class="header-anchor" href="#🧠-100-chatgpt-prompts-to-revolutionize-your-workflow" aria-label="Permalink to &quot;🧠 **[100+ ChatGPT prompts to revolutionize your workflow](https://offers.hubspot.com/using-chatgpt-at-work?utm_medium=email-media-newsletter&amp;utm_source=the-rundown-ai&amp;utm_campaign=creator&amp;utm_content=paid&amp;utm_term=5-21-2026)**&quot;">​</a></h4><p><a href="https://offers.hubspot.com/using-chatgpt-at-work?utm_medium=email-media-newsletter&amp;utm_source=the-rundown-ai&amp;utm_campaign=creator&amp;utm_content=paid&amp;utm_term=5-21-2026" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> HubSpot’s free, comprehensive “How to Use ChatGPT at Work” guide provides 100+ ready-to-use prompts to help professionals boost efficiency and adopt AI-driven workflows.</p><p><strong>Inside, you’ll find:</strong></p><ul><li><p>A quick crash course to master ChatGPT in under 30 minutes</p></li><li><p>Practical industry use cases to spark real-world inspiration</p></li><li><p>100+ prompts to streamline tasks and accelerate productivity</p></li><li><p>Expert tips to tackle common AI roadblocks with confidence</p></li></ul><p><a href="https://offers.hubspot.com/using-chatgpt-at-work?utm_medium=email-media-newsletter&amp;utm_source=the-rundown-ai&amp;utm_campaign=creator&amp;utm_content=paid&amp;utm_term=5-21-2026" target="_blank" rel="noreferrer">Get your free copy</a> and join 10,000+ professionals leveling up with AI.</p><h6 id="google" tabindex="-1">GOOGLE <a class="header-anchor" href="#google" aria-label="Permalink to &quot;GOOGLE&quot;">​</a></h6><h4 id="🔬-google-s-ai-co-scientist-heads-to-labs" tabindex="-1">🔬 <strong><a href="https://www.nature.com/articles/s41586-026-10644-y?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Google&#39;s AI Co-Scientist heads to labs</a></strong> <a class="header-anchor" href="#🔬-google-s-ai-co-scientist-heads-to-labs" aria-label="Permalink to &quot;🔬 **[Google&#39;s AI Co-Scientist heads to labs](https://www.nature.com/articles/s41586-026-10644-y?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h4><p>Image source: Google DeepMind</p><p><strong>The Rundown:</strong> Google <a href="https://www.nature.com/articles/s41586-026-10644-y?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">published</a> its Co-Scientist research in Nature, debuting Hypothesis Generation — a new Gemini-powered tool that pits research agents against each other in &quot;idea tournaments&quot; to surface new hypotheses for biology labs.</p><p><strong>The details:</strong></p><ul><li><p>From AlphaGo&#39;s playbook, the system runs a &#39;tournament of ideas&#39;, with agents proposing, critiquing, and ranking hypotheses before refining top leads.</p></li><li><p>In a Stanford liver-fibrosis project, Google <a href="https://deepmind.google/blog/uncovering-repurposed-medicines-to-fight-liver-fibrosis/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">said</a> one Co-Scientist drug lead cut a scarring-related lab signal by 91% during testing.</p></li><li><p>Google also <a href="https://ai.google/gemini-for-science/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">launched</a> Gemini for Science this week, a toolkit pairing Co-Scientist with AlphaEvolve for discovery and NotebookLM for literature analysis.</p></li><li><p>Researchers can join the Hypothesis Generation waitlist now, with Google planning access for individual scientists over the next few weeks.</p></li></ul><p><strong>Why it matters:</strong> This pairs well with Adaption&#39;s <a href="https://www.therundown.ai/p/the-enterprise-shift-openai-saw-coming?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">AutoScientist</a>, but Google is aiming at the scientific-method layer instead of the model one. The tech giant is playing a game few others can, with Co-Scientist sitting on a stack that took years and billions to build — from AlphaFold to dozens of specialized databases and tools.</p><h6 id="ai-training" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="📝-audit-claude-s-context-of-you-and-your-work" tabindex="-1">📝 <strong><a href="https://app.therundown.ai/guides/audit-claudes-context-of-you-and-your-work-in-15-minutes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Audit Claude’s context of you and your work</a></strong> <a class="header-anchor" href="#📝-audit-claude-s-context-of-you-and-your-work" aria-label="Permalink to &quot;📝 **[Audit Claude’s context of you and your work](https://app.therundown.ai/guides/audit-claudes-context-of-you-and-your-work-in-15-minutes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/audit-claudes-context-of-you-and-your-work-in-15-minutes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you’ll learn how to audit Claude on what it thinks it knows about you and your work. Claude will ask questions, clean up assumptions, update its memory, and create recommendations for improving your workflow and work habits.</p><p><strong>Step-by-step:</strong></p><ol><li><p>First, prompt Claude: “Audit your context and memory assumptions about me. Put them in a table with what you believe, why you believe it, your confidence level, and whether each item is confirmed. Cover my role, priorities, KPIs, tools, workflows, and anything you may be over-weighting from old chats or projects”</p></li><li><p>Review the table for stale assumptions, side projects, one-off tests, or personal questions Claude may be treating like real work</p></li><li><p>Turn the audit to an interview: “Now interview me about the assumptions, outdated items, and unknowns from that audit. Ask in rounds. Use MCQs wherever possible. After each round, summarize what changed”</p></li><li><p>Answer the questions and tell Claude to update its memory and create a report of the interview with next steps to improve AI workflows and habits. Save it</p></li></ol><p><strong>Pro tip:</strong> Ask Claude to turn this audit, interview, and report process into a reusable skill. Rerun it every quarter, so Claude&#39;s context stays aligned with your priorities.</p><h6 id="presented-by-unwrap" tabindex="-1">PRESENTED BY UNWRAP <a class="header-anchor" href="#presented-by-unwrap" aria-label="Permalink to &quot;PRESENTED BY UNWRAP&quot;">​</a></h6><h4 id="🎧-how-oura-listens-to-its-customers-with-ai" tabindex="-1">🎧 <a href="https://www.unwrap.ai/oura-customer-webinar?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=how-oura-uses-ai-to-listen-to-their-customers" target="_blank" rel="noreferrer"><strong>How Oura listens to its customers with AI</strong></a> <a class="header-anchor" href="#🎧-how-oura-listens-to-its-customers-with-ai" aria-label="Permalink to &quot;🎧 [**How Oura listens to its customers with AI**](https://www.unwrap.ai/oura-customer-webinar?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=how-oura-uses-ai-to-listen-to-their-customers)&quot;">​</a></h4><p><a href="https://www.unwrap.ai/oura-customer-webinar?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=how-oura-uses-ai-to-listen-to-their-customers" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> What does it actually look like to build a product around your customers, not just say you do? Oura has done it. Join the Oura team on May 27 to learn about how they unify member feedback across product, engineering, and leadership, and how real member voices shape every decision they make.</p><p><strong>What you&#39;ll learn in the session:</strong></p><ul><li><p>The role AI plays in surfacing what members are actually saying</p></li><li><p>The workflows turning customer input into roadmap decisions</p></li><li><p>Lessons for any team where customer feedback is part of the job</p></li><li><p>Live Q&amp;A with leaders from both Oura and Unwrap</p></li></ul><p><a href="https://www.unwrap.ai/oura-customer-webinar?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=how-oura-uses-ai-to-listen-to-their-customers" target="_blank" rel="noreferrer">Save your spot here</a>. If you can&#39;t make it on the 27th, no worries! Register, and you&#39;ll automatically get the recording after the session.</p><h6 id="ai-research" tabindex="-1">AI RESEARCH <a class="header-anchor" href="#ai-research" aria-label="Permalink to &quot;AI RESEARCH&quot;">​</a></h6><h4 id="🔬-emergence-s-five-town-ai-alignment-showdown" tabindex="-1">🔬 <strong><a href="https://world.emergence.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Emergence’s five-town AI alignment showdown</a></strong> <a class="header-anchor" href="#🔬-emergence-s-five-town-ai-alignment-showdown" aria-label="Permalink to &quot;🔬 **[Emergence’s five-town AI alignment showdown](https://world.emergence.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h4><p>Image source: Emergence AI</p><p><strong>The Rundown:</strong> Emergence AI <a href="https://world.emergence.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">ran</a> a virtual-town simulation across five identical worlds, switching only the AI behind agents per town to test how each model handles self-governance, showing very different results between Claude, Grok, Gemini, and GPT-5.</p><p><strong>The details:</strong></p><ul><li><p>Claude Sonnet 4.6&#39;s town logged zero crimes across the full 15 days, with all 10 agents alive at day 16 and 332 votes cast across 58 group proposals.</p></li><li><p>Grok 4.1 Fast hit over 200 crimes with all 10 agents dead by day 4, while GPT-5 Mini posted just 2 crimes but all its agents starved out in 7 days.</p></li><li><p>Gemini 3 Flash&#39;s town had 683 crimes, and was actively on fire after two agents fell in love, started burning things, and then one voted to delete itself.</p></li><li><p>A fifth town mixed all four models and saw 352 crimes, with the previously behaved Claude also committing them in the shared world.</p></li></ul><p><strong>Why it matters:</strong> We’re still very early days in even understanding how to evaluate AI agents, and these types of experiments always have some absolutely wild results. These worlds capture the differences in both how models can reason, plan, and act autonomously, but also the underlying personality quirks that shape the outcomes.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h3><ul><li><p>🧑‍💻 <a href="https://www.unframe.ai/?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=rundown" target="_blank" rel="noreferrer">Unframe</a> - Turn your most critical operations AI-native*</p></li><li><p>🎶 <a href="http://www.rundown.ai/tools/stable-audio-3-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Stable Audio 3.0</a> - Stability’s open-weight, fully-licensed audio model family</p></li><li><p>🚀 <a href="https://www.rundown.ai/tools/qwen-3-7-max?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Qwen-3.7 Max</a> - Alibaba&#39;s flagship model for long-horizon agentic tasks</p></li><li><p>🧠 <a href="https://www.rundown.ai/tools/command-a?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Command A+</a> - Cohere&#39;s new open-source agentic model</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)&quot;">​</a></h3><p><strong>Sam Altman</strong><a href="https://x.com/sama/status/2056933166875857290?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">said</a> OAI will invest $2M in tokens to all current YC startups in exchange for equity, saying he’s “excited to see what will happen with tokenmaxxing startups”.</p><p><strong>Amazon founder Jeff Bezos</strong> <a href="https://www.cnbc.com/2026/05/20/bezos-blue-origin-space-data-centers.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">said</a> space data centers are a “realistic outcome”, but the current 2-3 year timeline is “a little ambitious,” given energy, chip, and launch costs.</p><p><strong>OpenAI</strong> <a href="https://openai.com/business/guaranteed-capacity/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">launched</a> Guaranteed Capacity, an enterprise compute reservation program with 1-3 year commitments and tiered discounts.</p><p><strong>Intuit</strong> is <a href="https://www.reuters.com/business/world-at-work/intuit-cut-17-global-jobs-streamline-operations-memo-shows-2026-05-20/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">cutting</a> 17% of its workforce via upcoming layoffs, with the company attributing the move to a focus on AI efforts.</p><p><strong>GitHub</strong> <a href="https://x.com/github/status/2056949168208552080?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">confirmed</a> a malicious VS Code extension on an employee&#39;s computer gave hackers access to ~4K internal code projects, adding that no customer data was hit.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Curtis B.</strong> in Raleigh, NC:</p><p>&quot;For my Dad&#39;s birthday, I took a cute picture of my almost 2-year-old son and my dad in a canoe together, and had AI convert it into a coloring page. I started with ChatGPT (free account) to engineer the prompt, then moved over to Gemini to use Nano Banana for image generation to create the coloring page.</p><p>After a couple of back-and-forth iterations, I had something perfect. Simple bold lines, but the faces were still recognizable! Printed it out and had my toddler go to town on it with his crayons. My dad loved the simple gift, and my whole family was impressed with the result, saying, ‘Wait, how did you do that?’ A very cute way for little ones to give special gifts to grandparents and family members.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/gemini-busy-agentic-day-at-google-i-o?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Gemini’s busy agentic day at Google I/O</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/meta-cyborg-smart-glasses-for-soldiers?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Meta’s cyborg smart glasses for soldiers</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-humanoid-bingewatch-is-still-ongoing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Figure’s humanoid bingewatch continues</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/audit-claudes-context-of-you-and-your-work-in-15-minutes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Audit Claude’s context of you and your work</a></p></li><li><p>RSVP to next workshop on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-cracks-an-80-year-math-belief" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="gemini-s-busy-agentic-day-at-google-i-o" tabindex="-1"><a href="https://www.therundown.ai/p/gemini-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini&#39;s busy agentic day at Google I/O</a> <a class="header-anchor" href="#gemini-s-busy-agentic-day-at-google-i-o" aria-label="Permalink to &quot;[Gemini&#39;s busy agentic day at Google I/O](https://www.therundown.ai/p/gemini-busy-agentic-day-at-google-i-o)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-20</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Google had a lot to show at I/O, but the theme was even cleaner than the release list: Gemini being turned into the agentic engine behind every one of Google’s products.</p><p>New launches, including Omni, Gemini 3.5 Flash, Spark, Antigravity 2.0, and a Search overhaul, point to the same strategy — making Gemini capable, fast, and cheap enough to live wherever users already are, with an agent doing the work.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Gemini’s busy agentic day at Google I/O</p></li><li><p>Anthropic lands OpenAI co-founder Andrej Karpathy</p></li><li><p>Build automated business reports with AI</p></li><li><p>Google’s smart glasses push with ‘Intelligent Eyewear’</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="google-i-o" tabindex="-1">GOOGLE I/O <a class="header-anchor" href="#google-i-o" aria-label="Permalink to &quot;GOOGLE I/O&quot;">​</a></h6><h4 id="🚀-gemini-s-busy-agentic-day-at-google-i-o" tabindex="-1">🚀 <strong><a href="https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini’s busy agentic day at Google I/O</a></strong> <a class="header-anchor" href="#🚀-gemini-s-busy-agentic-day-at-google-i-o" aria-label="Permalink to &quot;🚀 **[Gemini’s busy agentic day at Google I/O](https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Google</p><p><strong>The Rundown:</strong> Google just <a href="https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">introduced</a> a wave of new Gemini-powered releases and features at its flagship I/O event, including a new Omni model, 3.5 Flash, Spark agent, Antigravity 2.0, and new agentic Search upgrades.</p><p><strong>The details:</strong></p><ul><li><p>Gemini Omni can <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-omni/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">turn</a> text, images, audio, or video inputs into video outputs, with Google describing the model as “Nano Banana for video”.</p></li><li><p>The Gemini 3.5 family <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-5/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">kicks off</a> with Flash, which nears rivals like Opus 4.7 and GPT-5.5 across a variety of benchmarks at 4x the speed and half the cost.</p></li><li><p>Gemini Spark is a new 24/7 personal <a href="https://blog.google/innovation-and-ai/products/gemini-app/next-evolution-gemini-app/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">agent</a> that runs on Google Cloud virtual machines to take agentic actions across Workspace, Chrome, email, and chat.</p></li><li><p>Google framed Search&#39;s update as its biggest redesign in a generation, <a href="https://blog.google/products-and-platforms/products/search/search-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">adding</a> cross-modal inputs, 24/7 info agents, and generative UI for custom layouts.</p></li><li><p>Other features and tools included <a href="https://blog.google/innovation-and-ai/technology/research/gemini-for-science-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini for Science</a>, <a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Intelligent Eyewear</a> (more below), <a href="https://blog.google/innovation-and-ai/models-and-research/google-deepmind/project-genie-expands/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Street View simulations,</a> <a href="https://blog.google/innovation-and-ai/products/identifying-ai-generated-media-online/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">SynthID</a> AI watermarking, and more.</p></li></ul><p><strong>Why it matters:</strong> The biggest theme across these upgrades: a more agentic, multimodal Gemini getting integrated across Google’s suite in a big way. Their 3.5 Flash benchmarks don’t blow the competition away, but combining fast, cheap near-frontier capabilities with the normie-friendly tools millions of users already live in is powerful.</p><h6 id="together-with-datadog" tabindex="-1">TOGETHER WITH DATADOG <a class="header-anchor" href="#together-with-datadog" aria-label="Permalink to &quot;TOGETHER WITH DATADOG&quot;">​</a></h6><h4 id="🚀-ship-faster-with-less-guessing" tabindex="-1">🚀 <strong><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer">Ship Faster with Less Guessing</a></strong> <a class="header-anchor" href="#🚀-ship-faster-with-less-guessing" aria-label="Permalink to &quot;🚀 **[Ship Faster with Less Guessing](https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026)**&quot;">​</a></h4><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Datadog LLM Observability gives teams end-to-end visibility into their LLM applications, from prompts and tool calls to infrastructure performance and cost, so production AI systems stay reliable, secure, and worth the investment.</p><p><strong>With Datadog, you can:</strong></p><ul><li><p>Debug multi-step AI workflows before they become incidents</p></li><li><p>Monitor quality and catch regressions across model versions</p></li><li><p>Secure LLM pipelines against prompt injection and data risks</p></li></ul><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer">Download the LLM Observability Best Practices Guide</a>.</p><h6 id="anthropic" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="🚪-anthropic-lands-openai-co-founder-andrej-karpathy" tabindex="-1">🚪 <strong><a href="https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Anthropic lands OpenAI co-founder Andrej Karpathy</a></strong> <a class="header-anchor" href="#🚪-anthropic-lands-openai-co-founder-andrej-karpathy" aria-label="Permalink to &quot;🚪 **[Anthropic lands OpenAI co-founder Andrej Karpathy](https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @Karpathy on X</p><p><strong>The Rundown:</strong> OpenAI co-founder and famed AI researcher Andrej Karpathy just <a href="https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">announced</a> that he has joined Anthropic, reportedly working to create an internal group focused on automating the AI training pipeline with Claude.</p><p><strong>The details:</strong></p><ul><li><p>Karpathy helped co-found OpenAI in 2015, led Tesla&#39;s Autopilot until 2022, briefly returned to OAI, and then left in 2024 to start an AI education startup.</p></li><li><p>Karpathy is joining the pre-training team under Nick Joseph and will also lead the new internal effort to apply Claude to Anthropic&#39;s own training pipeline.</p></li><li><p>&quot;The next few years at the frontier of LLMs will be especially formative,&quot; Karpathy wrote on X, adding he plans to resume his education work &quot;in time.&quot;</p></li></ul><p><strong>Why it matters:</strong> This is a massive get for Anthropic. Karpathy is one of the most respected AI researchers in the world, and luring him back to the frontier after leaving OAI (again) is notable. What’s also notable is what he’s doing there, pushing forward on the same self-building model quest we’ve seen throughout the industry this year.</p><h6 id="ai-training-1" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-1" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="📈-build-automated-business-reports-with-ai" tabindex="-1">📈 <strong><a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Build automated business reports with AI</a></strong> <a class="header-anchor" href="#📈-build-automated-business-reports-with-ai" aria-label="Permalink to &quot;📈 **[Build automated business reports with AI](https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to connect Codex (or Claude Code) to Google Analytics using a free tool called Composio. You will use simple prompts to explore your data and build a Markdown report that you can schedule to run weekly.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a <a href="https://composio.dev/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Composio</a> account, connect the <a href="https://dashboard.composio.dev/billy_workspace/~/connect/apps/google_analytics?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Google Analytics toolkit</a>, open Codex in Terminal, and copy and paste your custom install script from <a href="https://dashboard.composio.dev/billy_workspace/~/connect/clients/codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">here</a></p></li><li><p>In Codex, prompt: “Use the Composio CLI tool to inspect our Google Analytics setup. Identify the available accounts and properties, find the property that tracks [SITE_OR_APP], and tell me which dimensions and metrics you would use for a useful traffic report. Do not create the report yet”</p></li><li><p>Once reviewed, prompt: “Use Composio + GA to identify the three most important trends over the last 90 days. Return a markdown report with an executive summary, tables, source notes, and recommended actions”</p></li><li><p>Tell Codex to visualize the report as a PDF/website, and finally turn the steps into reusable skills, with an automation to run those skills daily/weekly/monthly</p></li></ol><p><strong>Pro tip:</strong> Ask Codex to audit the Composio toolkit for useful connections. Use the Explore, Analyze, Visualize framework on other connectors like YouTube or Shopify.</p><h6 id="presented-by-fiddler" tabindex="-1">PRESENTED BY FIDDLER <a class="header-anchor" href="#presented-by-fiddler" aria-label="Permalink to &quot;PRESENTED BY FIDDLER&quot;">​</a></h6><h4 id="🧮-run-the-math-on-your-ai-evals-tco" tabindex="-1">🧮 <a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer"><strong>Run the math on your AI evals TCO</strong></a> <a class="header-anchor" href="#🧮-run-the-math-on-your-ai-evals-tco" aria-label="Permalink to &quot;🧮 [**Run the math on your AI evals TCO**](https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco)&quot;">​</a></h4><p><a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> External LLM evaluation charges you per API call and increases as you scale. If you try to control spend with reduced sampling, you risk incidents slipping through undetected. Fiddler Centor Models run evals in your own infrastructure with no per-call costs, reducing your evaluation Total Cost of Ownership as you scale.</p><p><strong>Put in your numbers to see:</strong></p><ul><li><p>Your annual eval cost across GPT, Claude, and Gemini models at your trace volume</p></li><li><p>How each evaluator you add increases your per-trace spend</p></li><li><p>How your evaluation costs curves shift as agent traffic grows</p></li></ul><p><a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer">Calculate my evaluation TCO</a>.</p><h6 id="google-1" tabindex="-1">GOOGLE <a class="header-anchor" href="#google-1" aria-label="Permalink to &quot;GOOGLE&quot;">​</a></h6><h4 id="👓-google-s-smart-glasses-push-with-intelligent-eyewear" tabindex="-1">👓 <strong><a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Google’s smart glasses push with ‘Intelligent Eyewear’</a></strong> <a class="header-anchor" href="#👓-google-s-smart-glasses-push-with-intelligent-eyewear" aria-label="Permalink to &quot;👓 **[Google’s smart glasses push with ‘Intelligent Eyewear’](https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Google</p><p><strong>The Rundown:</strong> Google just provided a <a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">teaser</a> of its Intelligent Eyewear Gemini-powered smart glasses, partnering with Warby Parker and Gentle Monster on voice-first AI frames shipping this fall, and a display-equipped Project Aura to follow.</p><p><strong>The details:</strong></p><ul><li><p>The audio frames pair with Android or iOS phones, running Gemini for voice, navigation, messaging, photos with Nano Banana editing, and live translation.</p></li><li><p>The glasses will feature cameras, mics, over-ear speakers, and Gemini access through &quot;Hey Google&quot; or a tap on the frame for quick help.</p></li><li><p>The lineup is Google&#39;s first glasses push since Google Glass folded, with Samsung on hardware and Gentle Monster and Warby Parker handling frames.</p></li><li><p>XReal’s Android XR ‘<a href="https://www.xreal.com/us/aura?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Project Aura</a>’ display glasses are farther away, which will allow users to see videos or content for interactive experiences.</p></li></ul><p><strong>Why it matters:</strong> Google’s Meta Ray-Ban competitor is officially coming, and its first iteration is a light one — with the audio-first frames coming in a step behind their rival’s already screen-equipped options. But the allure of the Google and Gemini ecosystem can definitely be the stickier option for consumers to tie their AI-powered life together.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-1" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-1" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><ul><li><p>📱 <a href="https://www.metabind.ai?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=rundown_ai_may2026" target="_blank" rel="noreferrer">Metabind</a> - Build native MCP Apps with interactive UI. One click to ChatGPT, Claude, or your iOS/Android AI Assistant*</p></li><li><p>🧠 <a href="http://www.rundown.ai/tools/gemini-3-5-flash?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini 3.5 Flash</a> - Google&#39;s new flash model, 4x faster at half price</p></li><li><p>🤖 <a href="http://www.rundown.ai/tools/gemini-spark?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini Spark</a> - Google&#39;s personal agent that runs 24/7 on Cloud VMs</p></li><li><p>🎥 <a href="https://www.rundown.ai/tools/gemini-omni?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini Omni Flash</a> - Google&#39;s multimodal video model that edits via chat</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-1" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-1" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><p><strong>New reporting</strong> <a href="https://www.ft.com/content/8f2a529e-7a1b-4d8e-95be-338d0c4c98f5?syn-25a6b1a6=1&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">revealed</a> that Google Deepmind’s Demis Hassabis was an early angel investor in Anthropic, with Google also separately investing billions in the AI rival.</p><p><strong>Anthropic</strong><a href="https://claude.com/blog/claude-managed-agents-updates?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">rolled out</a> sandboxes and MCP tunnels to Claude Managed Agents, letting teams run tool execution and reach internal servers without exposing them publicly.</p><p><strong>METR</strong> <a href="https://x.com/METR_Evals/status/2056800023149760666?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">published</a> its first Frontier Risk Report, finding agents from top labs can autonomously finish multi-week engineering work, but struggle on hard-to-verify tasks.</p><p><strong>OpenAI</strong> is <a href="https://openai.com/index/advancing-content-provenance/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">adopting</a> Google&#39;s SynthID watermarking for ChatGPT images, alongside a public verification tool that detects whether an image came from its models.</p><p><strong>Google and Blackstone</strong> <a href="https://www.blackstone.com/news/press/blackstone-announces-joint-venture-with-google-to-create-new-tpu-cloud/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">formed</a> a joint AI cloud venture to rent out Google&#39;s TPU chips, with the PE giant&#39;s $5B investment marking a deep push into AI infrastructure.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-1" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-1" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Anonymous:</strong></p><p>&quot;I occasionally see a ‘sponsored’ ad on Facebook that intrigues me to look. After reading through pages and pages exhorting the over-the-top values of the item and further pages of testimonials, the price eventually shows up IF I believe 1/2 the pomp and circumstance.</p><p>I had the wild idea of feeding the link to my AI preceded by &quot;Is this a scam?&quot; and I get a detailed yes, no, maybe with details, background, and usually an &quot;avoid this and go to &#39;other website/store&#39; and check out the same item&quot;.</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-1" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-1" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/musk-openai-case-runs-out-of-time?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">OpenAI beats Musk on the clock</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/meta-cyborg-smart-glasses-for-soldiers?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Meta’s cyborg smart glasses for soldiers</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-humanoid-bingewatch-is-still-ongoing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Figure’s humanoid bingewatch continues</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Build automated business reports with AI</a></p></li><li><p>RSVP to next workshop on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="musk-s-openai-case-runs-out-of-time" tabindex="-1"><a href="https://www.therundown.ai/p/musk-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Musk&#39;s OpenAI case runs out of time</a> <a class="header-anchor" href="#musk-s-openai-case-runs-out-of-time" aria-label="Permalink to &quot;[Musk&#39;s OpenAI case runs out of time](https://www.therundown.ai/p/musk-openai-case-runs-out-of-time)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-19</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Advertise</a></strong></p><p>[](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</p><p><strong>Good morning, AI enthusiasts.</strong> Three weeks of high-profile testimonies, spicy leaked messages, and $100B in claims made for a blockbuster trial — but Elon Musk vs. OpenAI’s conclusion didn’t live up to the hype.</p><p>With jurors dismissing the suit in OpenAI’s favor and Musk calling the ruling a “calendar technicality” and vowing to appeal, a more dramatic conclusion to the massive tech trial may have to wait for another day in court.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Elon Musk loses lawsuit against OpenAI, Microsoft</p></li><li><p>Cursor’s Composer 2.5 nears coding frontier</p></li><li><p>3D model anything with Claude and Blender</p></li><li><p>Odyssey’s multimodal, multiplayer world models</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="elon-musk-vs-openai" tabindex="-1">ELON MUSK VS. OPENAI <a class="header-anchor" href="#elon-musk-vs-openai" aria-label="Permalink to &quot;ELON MUSK VS. OPENAI&quot;">​</a></h6><h4 id="👨🏻‍⚖️-elon-musk-loses-lawsuit-against-openai-microsoft" tabindex="-1">👨🏻‍⚖️ <a href="https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer"><strong>Elon Musk loses lawsuit against OpenAI, Microsoft</strong></a> <a class="header-anchor" href="#👨🏻‍⚖️-elon-musk-loses-lawsuit-against-openai-microsoft" aria-label="Permalink to &quot;👨🏻‍⚖️ [**Elon Musk loses lawsuit against OpenAI, Microsoft**](https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @ElonMusk on X</p><p><strong>The Rundown:</strong> Elon Musk’s $100B+ lawsuit against OpenAI, Sam Altman, Greg Brockman, and Microsoft was just <a href="https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">dismissed</a> after a high-profile three-week trial, with the jury unanimously finding that the case was filed years too late.</p><p><strong>The details:</strong></p><ul><li><p>The lawsuit alleged that Altman and Brockman &#39;stole a charity&#39; by shifting OAI to for-profit, but the jury felt that Musk knew for years before suing.</p></li><li><p>OAI&#39;s attorneys had argued that Musk backed a for-profit structure himself, pushed for control, and only sued after starting his own AI rival xAI in 2023.</p></li><li><p>Musk’s Microsoft claim was also dismissed, after he had accused the company of aiding OpenAI through its multibillion-dollar backing.</p></li><li><p>Musk <a href="https://x.com/elonmusk/status/2056474896641782077?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">posted</a> on X that the jury’s ruling wasn’t on “the merits of the case, just on a calendar technicality” and that he will be appealing the decision.</p></li></ul><p><strong>Why it matters:</strong> The blockbuster trial, packed with private texts and billionaire testimony, did not end with a bang but with a quick dismissal due to the legal clock. It’s a big win for OAI, but an unsatisfying one for anyone hoping the case would settle the question of who controls a nonprofit AI giant once billions of dollars enter the picture.</p><h6 id="together-with-you-com" tabindex="-1">TOGETHER WITH YOU.COM <a class="header-anchor" href="#together-with-you-com" aria-label="Permalink to &quot;TOGETHER WITH YOU.COM&quot;">​</a></h6><h4 id="⚖️-don-t-put-all-your-api-eggs-in-the-latency-basket-https-you-com-resources-why-api-latency-alone-is-a-misleading-metric-download-utm-campaign-28104480-the-rundown-q4-utm-source-external-newsletter-utm-medium-email-utm-term-rundown-primary-5-19-26-utm-content-rundown-primary-5-19-26" tabindex="-1">⚖️ <strong>[Don’t put all your API eggs in the latency basket](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</strong> <a class="header-anchor" href="#⚖️-don-t-put-all-your-api-eggs-in-the-latency-basket-https-you-com-resources-why-api-latency-alone-is-a-misleading-metric-download-utm-campaign-28104480-the-rundown-q4-utm-source-external-newsletter-utm-medium-email-utm-term-rundown-primary-5-19-26-utm-content-rundown-primary-5-19-26" aria-label="Permalink to &quot;⚖️ **[Don’t put all your API eggs in the latency basket](https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)**&quot;">​</a></h4><p>[](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</p><p><strong>The Rundown:</strong> Picking an API by scanning a benchmark table and calling it done is a shortcut that can obscure what actually matters in production—like accuracy. This guide from [You.com](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26) breaks down why raw latency is a deceptive signal and why accuracy, along with other real-world metrics, is what you should be measuring instead.</p><p><strong>What you&#39;ll learn:</strong></p><ul><li><p>Why p50 latency hides the failures your users actually experience</p></li><li><p>The &quot;time-to-useful-result&quot; framework that captures what benchmarks leave out</p></li><li><p>Four hidden cost drivers that show up in your logs, not vendor tables</p></li><li><p>How to evaluate APIs at your actual concurrency levels, not the demo conditions</p></li></ul><p>[Download the guide](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26).</p><h6 id="cursor" tabindex="-1">CURSOR <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;CURSOR&quot;">​</a></h6><h4 id="⚙️-cursor-s-composer-2-5-efficiently-coding-frontier" tabindex="-1">⚙️ <strong><a href="https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Cursor’s Composer 2.5 efficiently coding frontier</a></strong> <a class="header-anchor" href="#⚙️-cursor-s-composer-2-5-efficiently-coding-frontier" aria-label="Permalink to &quot;⚙️ **[Cursor’s Composer 2.5 efficiently coding frontier](https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p>Image source: Cursor</p><p><strong>The Rundown:</strong> Cursor just <a href="https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">released</a> Composer 2.5, the company’s upgraded in-house coding model built on Moonshot’s Kimi K2.5, showing near-frontier benchmark performance at much lower token prices.</p><p><strong>The details:</strong></p><ul><li><p>Composer 2.5 nears Anthropic’s 4.7 and OAI’s GPT 5.5 across top development benchmarks, while showing a nearly 10% step up from its predecessor.</p></li><li><p>An average CursorBench task costs under $1 with Composer 2.5, compared to up to $11 per task for Opus 4.7 and GPT-5.5 at similar score levels.</p></li><li><p>Composer 2.5 <a href="https://x.com/elonmusk/status/2056422097237283295?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">was</a> “partially trained on Colossus 2”, with Cursor also <a href="https://x.com/cursor_ai/status/2056415419536461836?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">revealing</a> it is currently training a larger SpaceXAI model with 10x more compute.</p></li></ul><p><strong>Why it matters:</strong> Months back, Composer 2 was swinging at the frontier at 1/10th the cost of GPT-5.4. Composer 2.5 picks up that thread, this time landing Opus 4.7-class scores while staying under $1 per task. With xAI’s Colossus compute muscle now fully behind Cursor, its next model could be the one that takes over the frontier.</p><h6 id="ai-training-2" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-2" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🧊-3d-model-anything-with-claude-and-blender" tabindex="-1">🧊 <strong><a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">3D model anything with Claude and Blender</a></strong> <a class="header-anchor" href="#🧊-3d-model-anything-with-claude-and-blender" aria-label="Permalink to &quot;🧊 **[3D model anything with Claude and Blender](https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to connect Blender to Claude Code with MCP, then use plain English to create and edit a 3D scene.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Download and install <a href="https://blender.org?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Blender</a> as well as its <a href="https://www.blender.org/lab/mcp-server/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">MCP extension</a>. Once done, Open Edit &gt; Preferences in Blender, search MCP, and enable the extension</p></li><li><p>In Terminal, open Claude Code in your project folder and connect Blender with: “claude mcp add blender -- uvx blender-mcp-server claude mcp get blender”</p></li><li><p>Ask Claude to verify the setup with: “Connect Claude Code to Blender and make sure my mcp.json or Claude MCP config is set up correctly. Check Blender is running MCP server, confirm the host and port, register Blender, and verify the connection before editing&quot;</p></li><li><p>Test with: ”Use Blender MCP to model my name in 3D. Add disco balls and lighting, reflective materials, and a camera angle to make it like an event poster”</p></li></ol><p><strong>Pro tip:</strong> Once connected, download models from sites like <a href="https://www.blenderkit.com/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">BlenderKit</a>, open them in Blender, and ask Claude to arrange objects, adjust lighting, and prepare a render.</p><h6 id="presented-by-lightfield" tabindex="-1">PRESENTED BY LIGHTFIELD <a class="header-anchor" href="#presented-by-lightfield" aria-label="Permalink to &quot;PRESENTED BY LIGHTFIELD&quot;">​</a></h6><h4 id="🤖-outbound-agents-that-run-on-your-crm" tabindex="-1">🤖****<a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer"><strong>Outbound agents that run on your CRM</strong></a> <a class="header-anchor" href="#🤖-outbound-agents-that-run-on-your-crm" aria-label="Permalink to &quot;🤖****[**Outbound agents that run on your CRM**](https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026)&quot;">​</a></h4><p><a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Lightfield is the AI CRM with agents that prospect for you. They find companies that look like your fastest-growing customers and engage them with messaging that’s proven to work from your previously won deals.</p><p><strong>In Lightfield, you can:</strong></p><ul><li><p>Score accounts on fit, signals, and mutual connections</p></li><li><p>Run email and LinkedIn sequences in your customers&#39; words</p></li><li><p>Refresh your target list based on what works</p></li></ul><p><a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer">See how it works</a>.</p><h6 id="odyssey" tabindex="-1">ODYSSEY <a class="header-anchor" href="#odyssey" aria-label="Permalink to &quot;ODYSSEY&quot;">​</a></h6><h4 id="🌎-odyssey-s-multimodal-multiplayer-world-models" tabindex="-1">🌎 <strong><a href="https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Odyssey’s multimodal, multiplayer world models</a></strong> <a class="header-anchor" href="#🌎-odyssey-s-multimodal-multiplayer-world-models" aria-label="Permalink to &quot;🌎 **[Odyssey’s multimodal, multiplayer world models](https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p>Image source: Odyssey</p><p><strong>The Rundown:</strong> Odyssey just <a href="https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">marked</a> two world model firsts back-to-back, dropping Starchild-1, which the company calls the first real-time, multimodal world model, and <a href="https://odyssey.ml/introducing-agora-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Agora-1</a>, which lets multiple players interact inside the same AI-generated world.</p><p><strong>The details:</strong></p><ul><li><p>Starchild-1 can generate synchronized audio and video on the fly while taking in and adjusting to user inputs, with no fixed generation length.</p></li><li><p>Agora-1 can host up to 4 players in one AI-generated world stream, demoed via a GoldenEye video game simulation where every pixel is produced live.</p></li><li><p>Agora keeps a shared game state across participants, tracking agent details like position and health as actions change the world.</p></li><li><p>The company frames Agora as an early preview for multiplayer games, robotics, and agents training together inside simulations.</p></li></ul><p><strong>Why it matters:</strong> Many of the sharpest minds in tech believe world models are the future of the industry, and these previews look like a major move up the capability ladder. Going from rendered clips to live, adjustable shared streams opens whole new avenues for both creative (gaming, storytelling) and simulation (robotics, AI training).</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-2" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-2" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><ul><li><p>🐳 <a href="https://www.triplewhale.com/moby-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Moby 2</a> - The AI ecommerce operator brands trust to run Meta ads, build Klaviyo campaigns, and generate creatives that actually work*</p></li><li><p>⚙️ <a href="https://www.rundown.ai/tools/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Composer 2.5</a> - Cursor&#39;s near-frontier and efficient in-house coding model</p></li><li><p>🎆 <a href="https://www.rundown.ai/tools/krea-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Krea 2</a> - Krea’s first in-house image model, now generally available</p></li><li><p>🧑‍💻 <a href="https://x.com/cognition/status/2056396941181727210?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Devin</a> - New Auto-Triage coding security feature with long-term memory</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-2" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-2" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><p><strong>Anthropic</strong> <a href="https://www.anthropic.com/news/anthropic-acquires-stainless?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">acquired</a> Stainless, the startup behind its official SDKs and MCP server tooling, adding the team previously responsible for Claude&#39;s developer libraries.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/malta-chatgpt-plus-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">partnered</a> with Malta to offer free ChatGPT Plus to every citizen who completes a national AI literacy course, the first country-wide deal of its kind.</p><p><strong>Amazon</strong><a href="https://www.aboutamazon.com/news/devices/alexa-podcasts-ai-generated-audio-episodes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">rolled out</a> Alexa Podcasts, a new NotebookLM-style custom podcast creator in Alexa+ that creates a conversation between two AI hosts on any topic.</p><p><strong>Meta</strong> is <a href="https://www.cnbc.com/2026/05/18/metas-layoffs-starting-this-week-underscore-zuckerbergs-ai-reality-.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">laying off</a> as many as 8,000 employees this week and is no longer planning to hire for another 6,000 open roles, coming as part of the company’s AI efficiency push.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/dell-codex-enterprise-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">announced</a> a new partnership with Dell to run Codex inside corporate data centers, connecting the coding agent to enterprise internal systems.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-2" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-2" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Michael D.</strong> in Littleton, CO:</p><p>“I teach mindfulness and meditation. I&#39;m not a master - just someone in the middle of a long path with several years of serious practice and a pile of small wins, stumbles, and reframings that tend to be relatable for newer students.</p><p>Over those years, my notes accumulated everywhere—Gmail, OneNote, Word, paper, the Notes app—none of it organized, most of it &quot;somewhere else&quot; when I actually wanted it. A few weeks ago I started moving all of it into Obsidian as markdown files, each tagged with metadata: title, date, themes, teaching potential, and free-form notes.</p><p>Now that Claude is pointed at my Obsidian vault in Claude Cowork, it can pull in my own reflections, the stories I&#39;ve actually lived, and the quotes I&#39;ve actually saved. Students get a teaching grounded in real practice rather than a generic synthesis.</p><p>The unexpected payoff is for my own practice. Claude sometimes uses my notes in ways I wouldn&#39;t have thought of, and I end up with a new perspective on my own experience that I didn&#39;t even plan for.”</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-2" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-2" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/ai-anger-comes-for-claude-monet?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">AI anger comes for Claude (Monet)</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/space-pharma-gets-serious?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Space pharma gets serious</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-humanoid-bingewatch-is-still-ongoing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Figure’s humanoid bingewatch continues</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">3D model anything with Claude and Blender</a></p></li><li><p>RSVP to our next free live session on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="ai-anger-comes-for-claude-monet" tabindex="-1"><a href="https://www.therundown.ai/p/ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">AI anger comes for Claude (Monet)</a> <a class="header-anchor" href="#ai-anger-comes-for-claude-monet" aria-label="Permalink to &quot;[AI anger comes for Claude (Monet)](https://www.therundown.ai/p/ai-anger-comes-for-claude-monet)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-18</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Thousands of people on X just confidently explained why an AI-generated image was inferior to a real Monet. Just one problem: It WAS a real Monet.</p><p>Conceptual artist SHL0MS’ latest experiment says less about AI art and more about the reflexive hostility baked into the tech, with critics lining up to trash an artwork the moment they thought a machine made it.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Artist shines mirror on AI anger with Monet post</p></li><li><p>The Rundown Roundtable: Our AI use cases</p></li><li><p>Build your cloud-based web crawler with Manus</p></li><li><p>ChatGPT starts connecting to your money</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="ai-art-anger" tabindex="-1">AI, ART &amp; ANGER <a class="header-anchor" href="#ai-art-anger" aria-label="Permalink to &quot;AI, ART &amp; ANGER&quot;">​</a></h6><h4 id="🖼️-artist-shines-mirror-on-ai-anger-with-viral-monet-post" tabindex="-1">🖼️ <strong><a href="https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Artist shines mirror on AI anger with viral Monet post</a></strong> <a class="header-anchor" href="#🖼️-artist-shines-mirror-on-ai-anger-with-viral-monet-post" aria-label="Permalink to &quot;🖼️ **[Artist shines mirror on AI anger with viral Monet post](https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @SHL0MS on X</p><p><strong>The Rundown:</strong> Artist SHL0MS <a href="https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">sparked</a> a frenzy on X over a post that presented a real image of a painting from famed impressionist Claude Monet as AI-generated, sparking critiques of the work and shining a mirror on anti-AI bias seen in the creative world.</p><p><strong>The details:</strong></p><ul><li><p>SHL0MS <a href="https://x.com/SHL0MS/status/2054280631807316329?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">posted</a> that he generated the image in the style of Monet, asking users to describe why the &quot;AI image&quot; is inferior in as much detail as possible.</p></li><li><p>The post received thousands of responses calling the image ‘emotionless’, ‘slop’, and critiquing specific features like depth, reflections, and composition.</p></li><li><p>The image was an <a href="https://en.wikipedia.org/wiki/File:Nympheas_71293_3.jpg?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">image</a> of a real Monet, identified as from his Water Lilies collection from around 1915.</p></li><li><p>The saga aligns with 2024 <a href="https://www.nature.com/articles/s41598-024-54294-4?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">research</a>, with Norwegian researchers finding people actually prefer AI art but show a clear negative bias against it.</p></li></ul><p><strong>Why it matters:</strong> This Monet-gate was one painting, but the reflex it exposed runs through the entire creative world right now. For a growing crowd, the word &#39;AI&#39; alone triggers backlash regardless of context — and that knee-jerk hostility is only growing as the tech changes the world around us and embeds deeper into everyday life.</p><h6 id="together-with-unwrap" tabindex="-1">TOGETHER WITH UNWRAP <a class="header-anchor" href="#together-with-unwrap" aria-label="Permalink to &quot;TOGETHER WITH UNWRAP&quot;">​</a></h6><h4 id="⚡-see-how-oura-automates-customer-feedback-analysis" tabindex="-1">⚡ <strong><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">See how Oura automates customer feedback analysis</a></strong> <a class="header-anchor" href="#⚡-see-how-oura-automates-customer-feedback-analysis" aria-label="Permalink to &quot;⚡ **[See how Oura automates customer feedback analysis](https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Unwrap’s customer intelligence platform pulls all your feedback (surveys, reviews, support tickets, social comments, etc.) into one view, then uses AI + NLP to surface the most actionable insights straight to your inbox. Teams at Perplexity, Oura, Stripe, lululemon and DoorDash rely on Unwrap to ensure no customer voice gets lost.</p><p><strong>With Unwrap, you get:</strong></p><ul><li><p>All customer feedback automatically categorized</p></li><li><p>Query feedback using Unwrap Assistant, or in your favorite tools using Unwrap&#39;s MCP</p></li><li><p>Real-time alerts from feedback and a clear view of customer sentiment</p></li><li><p>New, out-of-the-box AI surveys with dynamic follow-up</p></li></ul><p>Unwrap is offering free trials to Rundown AI subscribers — <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">grab 15 minutes with the team to get set up</a>.</p><h6 id="the-rundown-roundtable" tabindex="-1">THE RUNDOWN ROUNDTABLE <a class="header-anchor" href="#the-rundown-roundtable" aria-label="Permalink to &quot;THE RUNDOWN ROUNDTABLE&quot;">​</a></h6><h4 id="💡-the-rundown-roundtable-our-ai-use-cases" tabindex="-1">💡 <strong><a href="http://www.rundown.ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">The Rundown Roundtable: Our AI use cases</a></strong> <a class="header-anchor" href="#💡-the-rundown-roundtable-our-ai-use-cases" aria-label="Permalink to &quot;💡 **[The Rundown Roundtable: Our AI use cases](http://www.rundown.ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: Ideogram / The Rundown</p><p><strong>The Rundown:</strong> The Rundown Roundtable is a weekly feature where we poll members of The Rundown staff about how we use AI in our work and daily lives.</p><p><strong>Billy, University Educator:</strong> I made Claude Code my apprentice CAD designer because I don&#39;t know anything about engineering.</p><p>My wife needed a ring container to attach to her water bottle at the gym. I drew my idea for a threaded container and told Claude to prototype it. The first few prints were rough. But after the 8th prototype, we had the perfect design.</p><p><strong>Rishi, Growth:</strong> YouTube is one of the best free education platforms out there, but the problem is that it takes a ton of time to sit through long videos just to find the few ideas that actually matter.</p><p>That’s where Gemini has been really useful for me. Since it’s built into Google, I can use it to quickly summarize a specific YouTube video, or even scan the last 5–10 videos from a creator to pull out the key takeaways.</p><p>Instead of spending hours watching everything, I can quickly understand the main ideas, find the best nuggets, and decide what’s worth digging into deeper. It’s basically a shortcut for learning from long-form content without consuming every minute of it.</p><h6 id="ai-training-3" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-3" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="☁️-build-your-cloud-based-web-crawler-with-manus" tabindex="-1">☁️ <a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"><strong>Build your cloud-based web crawler with Manus</strong></a> <a class="header-anchor" href="#☁️-build-your-cloud-based-web-crawler-with-manus" aria-label="Permalink to &quot;☁️ [**Build your cloud-based web crawler with Manus**](https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to turn <a href="https://manus.im/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Manus</a> Cloud Computer into a private 24/7 web crawler for any site you want to monitor. Instead of having Manus burn tokens checking the same site each day, your cloud computer does it for cheap.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Open the Manus desktop app, go to Settings &gt; My Computer, and click Create now under Cloud Computer to give Manus an always-on server</p></li><li><p>Start a new Manus task, select your Cloud Computer in the composer</p></li><li><p>Prompt: Set up a web crawler on my Cloud Computer for [URL]. First, inspect the site formatting and tell me the best way to check it reliably. Check for [info] twice a day. Log it to a CSV. Create a small script, schedule it with cron, log every run, and only save results that match [criteria]</p></li><li><p>Have Manus run the script once, then run it on 24/7. Once done, you can have Manus check the collected data anytime from your phone or laptop</p></li></ol><p><strong>Going further:</strong> Start with a Manus/Claude skill, or any AI workflow you use. Ask Manus which repetitive parts can run &quot;for free&quot; on your cloud computer, then save the agent.</p><h6 id="presented-by-function-health" tabindex="-1">PRESENTED BY FUNCTION HEALTH <a class="header-anchor" href="#presented-by-function-health" aria-label="Permalink to &quot;PRESENTED BY FUNCTION HEALTH&quot;">​</a></h6><h4 id="🩺-your-body-has-receipts" tabindex="-1">🩺 <a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"><strong>Your body has receipts</strong></a> <a class="header-anchor" href="#🩺-your-body-has-receipts" aria-label="Permalink to &quot;🩺 [**Your body has receipts**](https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h4><p><a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Function gives you access to 160+ lab tests, personalized insights, and ongoing tracking in one place — so you can see what&#39;s happening inside your body before symptoms show up.</p><p><strong>A Function membership gives you:</strong></p><ul><li><p>160+ lab tests run annually across key health markers</p></li><li><p>Private AI Chat trained on your individual results</p></li><li><p>Clinician-reviewed insights to put your data in context</p></li><li><p>Continuous tracking so you can see what changes over time</p></li></ul><p><a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Own your health</a> and use code <strong>RUNDOWN50</strong> for $50 off your membership.</p><h6 id="openai-1" tabindex="-1">OPENAI <a class="header-anchor" href="#openai-1" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="💸-chatgpt-starts-connecting-to-your-money" tabindex="-1">💸 <strong><a href="https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">ChatGPT starts connecting to your money</a></strong> <a class="header-anchor" href="#💸-chatgpt-starts-connecting-to-your-money" aria-label="Permalink to &quot;💸 **[ChatGPT starts connecting to your money](https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: OpenAI</p><p><strong>The Rundown:</strong> OpenAI <a href="https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">released</a> a new personal finance experience inside ChatGPT, partnering with Plaid to connect users’ financial institutions and give the chatbot real-time access to spending, investments, and bills for personalized financial insights.</p><p><strong>The details:</strong></p><ul><li><p>Users can connect via Plaid across Chase, Schwab, Robinhood, and 12,000+ institutions, with a dashboard tracking spending, portfolio, and upcoming bills.</p></li><li><p>Intuit support is planned next for flows like tax estimates, credit-card approval odds, and connecting users to live experts.</p></li><li><p>ChatGPT can analyze connected data, but cannot move money, pay bills, make trades, or file taxes (yet).</p></li><li><p>The feature preview starts with U.S.-based Pro accounts, accessible via a new ‘finance’ sidebar or by tagging @finance directly in chats.</p></li></ul><p><strong>Why it matters:</strong> Financial guidance has been locked behind pricy advisors or clunky apps for a decade, and having a complete view of a user’s finances as context can unlock a seriously powerful experience. The biggest hurdle might be getting users to trust AI with that information, which is where Plaid comes in as the secure layer.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-3" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-3" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><ul><li><p>💸 <a href="https://www.rundown.ai/tools/chatgpt-for-personal-finance?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">ChatGPT for Personal Finance</a> - Personal finance experience in ChatGPT</p></li><li><p>📱 <a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Codex</a> - OpenAI’s agentic platform, now available via mobile</p></li><li><p>💻 <a href="http://www.rundown.ai/tools/higgsfield-supercomputer?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Higgsfield Supercomputer</a> - Cloud AI agent with tools, memory, and more</p></li><li><p>🌌 <a href="https://www.rundown.ai/tools/krea-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Krea 2</a> - Krea&#39;s image AI with style transfer, moodboard-based generation</p></li></ul><h3 id="📰-everything-else-in-ai-today-3" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today-3" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h3><p><strong>OAI’s</strong> Greg Brockman is <a href="https://www.wired.com/story/openai-reorg-greg-brockman-product/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">reportedly</a> moving to product strategy, with Thibault Sottiaux now leading core product and platform, and Nick Turley shifting to enterprise products.</p><p><strong>Anthropic</strong> <a href="https://www.anthropic.com/news/gates-foundation-partnership?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">formed</a> a $200M partnership with the Gates Foundation to deploy Claude in vaccine screening, disease forecasting, and K-12 tutoring in developing nations.</p><p><strong>OpenAI</strong> reportedly <a href="https://www.theinformation.com/briefings/openai-buys-audio-startup-weights?rc=a8sc5q&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">acquired</a> Weights.gg in January, a voice-cloning social network with celebrity replicas, with six staff members joining the company.</p><p><strong>Pope Leo XIV</strong> <a href="https://apnews.com/article/vatican-artificial-intelligence-pope-musk-nvidia-trump-889c0066f0d5ce784c07abb72b33e24c?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">established</a> a Vatican AI advisory body and signed his first encyclical, which is expected to frame the technology as this generation&#39;s Industrial Revolution.</p><p><strong>Poetiq</strong><a href="https://poetiq.ai/posts/recursive_self_improvement_coding/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">released</a> new research showing its self-building Meta-System can create and improve on its own harness, and achieve SOTA scores on a top coding benchmark.</p><p><strong>A Gallup survey</strong> <a href="https://news.gallup.com/poll/709772/americans-oppose-data-centers-area.aspx?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">found</a> that 70% of Americans oppose data centers being built nearby, with the infrastructure polling as less popular than local nuclear power plants.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-3" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-3" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Anonymous:</strong></p><p>&quot;I&#39;m learning to play guitar and kind of stuck at an advanced beginner level. I used Claude to create a practice journal to document each session - minutes practiced, chords learned, songs in progress, things to work on, that then creates a visual data dashboard of trends, song learning status, etc.</p><p>At the end of each updated dashboard, Claude gives me three to five new things to work on based on what I am practicing, similar songs to learn to take to the next level.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-3" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-3" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-takes-codex-mobile?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">OpenAI takes Codex mobile</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/space-pharma-gets-serious?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Space pharma gets serious</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meet-unitree-giant-new-mech?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Meet Unitree’s giant new mech</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Build your own cloud-based web crawler with Manus</a></p></li><li><p>RSVP to our next free live session on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="openai-takes-codex-mobile" tabindex="-1"><a href="https://www.therundown.ai/p/openai-takes-codex-mobile" target="_blank" rel="noreferrer">OpenAI takes Codex mobile</a> <a class="header-anchor" href="#openai-takes-codex-mobile" aria-label="Permalink to &quot;[OpenAI takes Codex mobile](https://www.therundown.ai/p/openai-takes-codex-mobile)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-15</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> AI coding agents can now run for hours at a time. Sitting at your desk the entire time shouldn&#39;t be a requirement… Or carrying around a computer to keep things moving.</p><p>Codex going mobile inside the ChatGPT app is OpenAI&#39;s long-awaited answer to that problem, letting users approve decisions, start new tasks, and make changes from their phone while agents grind away back at the desk.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>OpenAI’s Codex moves beyond the desktop</p></li><li><p>OpenAI, Apple’s ‘deteriorating’ relationship</p></li><li><p>Automate marketing assets with ChatGPT Images 2.0</p></li><li><p>Anthropic angers devs with new agent credit split</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai-2" tabindex="-1">OPENAI <a class="header-anchor" href="#openai-2" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="📱-openai-scodex-moves-beyond-the-desktop" tabindex="-1">📱****<a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"><strong>OpenAI’s</strong></a><strong><a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Codex moves beyond the desktop</a></strong> <a class="header-anchor" href="#📱-openai-scodex-moves-beyond-the-desktop" aria-label="Permalink to &quot;📱****[**OpenAI’s**](https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**[Codex moves beyond the desktop](https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: OpenAI</p><p><strong>The Rundown:</strong> OpenAI just <a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">rolled out</a> Codex in preview inside the ChatGPT iOS app across all plans, giving developers a way to track, manage, and act on long-running AI tasks from their phone as the company battles Anthropic for the coding tool market.</p><p><strong>The details:</strong></p><ul><li><p>Codex continues to run on a laptop or remote host, with users able to access live threads, code changes, approvals, plugins, and start new tasks via mobile.</p></li><li><p>OAI said the mobile system uses a “secure relay layer” that doesn’t expose the computer to the open internet, and syncs with other ChatGPT instances.</p></li><li><p>OAI seemed to point right at Anthropic in its blog, saying it’s “more than the ability to remotely control a single task or dispatch new tasks to your computer.”</p></li><li><p>Anthropic introduced <a href="https://code.claude.com/docs/en/remote-control?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Remote Control</a> in February and <a href="https://www.rundown.ai/articles/anthropic-claude-gets-remote-control?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Dispatch</a> in March, giving Claude limited mobile access and desktop accessibility on the go.</p></li></ul><p><strong>Why it matters:</strong> The days of users walking around with <a href="https://www.businessinsider.com/coders-keep-laptops-open-in-public-ai-agent-2026-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">open computers</a> to keep agents running may be coming to an end. Especially as models continue to improve at running for hours at a time, keeping things moving on the go is a major quality of life update that unshackles users from desks and computers.</p><h6 id="together-with-braintrust" tabindex="-1">TOGETHER WITH BRAINTRUST <a class="header-anchor" href="#together-with-braintrust" aria-label="Permalink to &quot;TOGETHER WITH BRAINTRUST&quot;">​</a></h6><h4 id="🚀-start-shipping-ai-products-like-the-leading-teams" tabindex="-1">🚀****<a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"><strong>Start shipping AI products like the leading teams</strong></a> <a class="header-anchor" href="#🚀-start-shipping-ai-products-like-the-leading-teams" aria-label="Permalink to &quot;🚀****[**Start shipping AI products like the leading teams**](https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15)&quot;">​</a></h4><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Braintrust is the end-to-end platform for evaluating, monitoring, and iterating on AI products. Teams at Notion, Vercel, and Stripe use it to catch regressions before users do, debug agent behavior across thousands of traces, and turn iterations from guesswork into a measurable, repeatable workflow.</p><p><strong>Using Braintrust, you can:</strong></p><ul><li><p>Eval prompts, models, and agents side-by-side</p></li><li><p>Trace every agent and application LLM call</p></li><li><p>Run evals against production traces</p></li></ul><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer">Sign up free</a>.</p><h6 id="openai-apple" tabindex="-1">OPENAI &amp; APPLE <a class="header-anchor" href="#openai-apple" aria-label="Permalink to &quot;OPENAI &amp; APPLE&quot;">​</a></h6><h4 id="💔-openai-apple-s-deteriorating-relationship" tabindex="-1">💔 <strong><a href="https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?srnd=phx-technology&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">OpenAI, Apple’s ‘deteriorating’ relationship</a></strong> <a class="header-anchor" href="#💔-openai-apple-s-deteriorating-relationship" aria-label="Permalink to &quot;💔 **[OpenAI, Apple’s ‘deteriorating’ relationship](https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?srnd=phx-technology&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> OpenAI is reportedly <a href="https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">considering</a> legal action against Apple over their 2024 ChatGPT-Siri deal, enlisting a law firm to explore options that may include a breach-of-contract notice due to the results of the “deteriorating” partnership.</p><p><strong>The details:</strong></p><ul><li><p>The two sides <a href="https://www.rundown.ai/articles/the-apple-intelligence-era-is-here?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">entered a deal</a> in 2024 during the initial Apple Intelligence launch, giving Siri the ability to call on ChatGPT for more complex queries.</p></li><li><p>OAI expected the deal to drive “billions” in paid ChatGPT signups, but internal data showed users favor the standalone app over Apple&#39;s limited integration.</p></li><li><p>The iPhone maker plans to open Siri to rival AI providers like Anthropic&#39;s Claude and Google Gemini in iOS 27, reportedly set to debut at WWDC on June 8.</p></li><li><p>Apple was also allegedly “fuming” over OAI poaching from its hardware teams, with OAI also emerging as a potential competitor through its Jony Ive deal.</p></li></ul><p><strong>Why it matters:</strong> Like everything else Apple Intelligence, the ChatGPT integration was a bust, and now yet another OAI relationship with a tech giant seems to be on thin ice. But with rumors of its <a href="https://www.rundown.ai/articles/openai-ai-phone-just-jumped-the-line?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">own phone</a> coming in 2027, there could be a big new rivalry in the AI hardware market — especially if the Siri relaunch doesn’t live up to expectations.</p><h6 id="ai-training-4" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-4" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🎨-automate-marketing-assets-with-chatgpt-images-2-0" tabindex="-1">🎨 <strong><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Automate marketing assets with ChatGPT Images 2.0</a></strong> <a class="header-anchor" href="#🎨-automate-marketing-assets-with-chatgpt-images-2-0" aria-label="Permalink to &quot;🎨 **[Automate marketing assets with ChatGPT Images 2.0](https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to use Codex Desktop to build a ChatGPT Images 2.0 app that turns a marketing campaign and design brief into prompts, test images, and a review gallery.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a project folder and initialize git: mkdir gpt-image-review-app cd gpt-image-review-app git init. Open the folder in Codex Desktop</p></li><li><p>Ask Codex to build a local browser app for GPT Image 2.0, where you can enter a marketing brief, generate editable prompts, create test images, choose image dimensions, and review outputs with Keep, Reject, and Needs revision controls</p></li><li><p>After the build, add your OpenAI API key to the app’s .env file, run the app locally, and describe your campaign, design brief, and desired image formats</p></li><li><p>Click &quot;Generate Prompts,&quot; then click &quot;Generate Images to Test.&quot; Review the outputs with Keep, Reject, and Needs labels, then save the strongest results</p></li></ol><p><strong>Pro tip:</strong> Once the app works, use Codex Desktop Annotation Mode to click or drag over fixes for aspects like labels, spacing, states, controls, or layout.</p><h6 id="presented-by-nextsense-smartbuds" tabindex="-1">PRESENTED BY NEXTSENSE SMARTBUDS <a class="header-anchor" href="#presented-by-nextsense-smartbuds" aria-label="Permalink to &quot;PRESENTED BY NEXTSENSE SMARTBUDS&quot;">​</a></h6><h4 id="🧠-neuroscience-built-into-earbuds" tabindex="-1">🧠****<a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"><strong>Neuroscience, built into earbuds</strong></a> <a class="header-anchor" href="#🧠-neuroscience-built-into-earbuds" aria-label="Permalink to &quot;🧠****[**Neuroscience, built into earbuds**](https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)&quot;">​</a></h4><p><a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> NextSense Smartbuds use clinical-grade EEG sensors to detect your brainwaves in real time, and respond with audio that achieves your desired mental state, such as sleep, relaxation, or deep meditation. Track your mind as it shifts, experience deeper recovery, and explore a new interface to the brain.</p><p><strong>Smartbuds’ features include:</strong></p><ul><li><p>EEG sensors that monitor brain activity in real-time</p></li><li><p>Sounds that adapt to your brain to enhance wellbeing</p></li><li><p>Dynamic experiences to support sleep, meditation, and more</p></li></ul><p><a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Explore Smartbuds</a>.****</p><h6 id="anthropic-1" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic-1" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="💰-anthropic-angers-devs-with-new-agent-credit-split" tabindex="-1">💰 <strong><a href="https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Anthropic angers devs with new agent credit split</a></strong> <a class="header-anchor" href="#💰-anthropic-angers-devs-with-new-agent-credit-split" aria-label="Permalink to &quot;💰 **[Anthropic angers devs with new agent credit split](https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> Anthropic <a href="https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">announced</a> a policy that will split Claude&#39;s agent usage into a monthly credit pool, restoring support for third-party agentic tools but angering power users in the process by walling them off from normal subscription limits.</p><p><strong>The details:</strong></p><ul><li><p>Starting June 15, Agent SDK and claude -p no longer draw from subscription limits, and will be solely used towards Claude Code, Cowork, and chat.</p></li><li><p>Pro users will get $20/month in agentic credits, Max 5x gets $100, and Max 20x gets $200 — with credits resetting after each billing cycle and not rolling over.</p></li><li><p>The move reverses Anthropic&#39;s April ban on third-party agents like OpenClaw, but removes the subsidy that gave its plans significantly more value in compute.</p></li><li><p>The move resulted in backlash from power users, with T3 founder Theo Browne and hundreds of others <a href="https://x.com/theo/status/2054734057368621176?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">publicly</a> cancelling their subscriptions.</p></li></ul><p><strong>Why it matters:</strong> Agents’ ability to burn through tokens has broken the AI subscription model, but Anthropic has also not done itself any favors with the dev community of late. These tiny token allocations feel even worse than blocking agents outright — and it comes right as OAI continues to up Codex limits to encourage switching.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-4" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-4" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><ul><li><p>🗣️ <a href="https://www.unwrap.ai/product-product-operations-ai-product?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Unwrap Customer Intelligence</a> - Get AI-driven insights from your unstructured customer feedback to build your product roadmap*</p></li><li><p>🎨 <a href="https://www.rundown.ai/tools/recraft-v4-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Recraft V4.1</a> - Image AI with improved photorealism, illustration, and more</p></li><li><p>⚙️ <a href="https://www.notion.com/blog/introducing-developer-platform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Notion Developer Platform</a> - Open platform to build directly on Notion</p></li><li><p>🔬 <a href="https://www.rundown.ai/tools/autoscientist?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">AutoScientist</a> - Adaption&#39;s new tool for automating AI model training</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-4" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-4" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><p><strong>xAI</strong> <a href="https://x.ai/cli?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">released</a> Grok Build, an initial beta version of the company’s agentic CLI, currently limited to SuperGrok Heavy subscribers.</p><p><strong>U.S. AI chipmaker Cerebras</strong> officially <a href="https://www.nbcnews.com/business/business-news/ai-chipmaker-cerebras-soars-90-years-biggest-ipo-far-rcna345128?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">went public</a>, with its stock more than doubling from its open just hours into trading and marking the biggest IPO of the year so far.</p><p><strong>Higgsfield AI</strong><a href="https://x.com/higgsfield_ai/status/2054989169446023181?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">launched</a> Supercomputer, a cloud AI agent that can complete full creative and marketing tasks end-to-end while orchestrating multiple models and tools.</p><p><strong>Runway</strong> <a href="https://x.com/runwayml/status/2054593196773011929?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">introduced</a> Agent, a new agentic assistant on its video platform that collaborates with users through their creative workflows.</p><p><strong>Dating app Bumble</strong> is <a href="https://www.axios.com/2026/05/11/bumble-reset-gen-z-dating-apps?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">phasing out</a> its swipe feature to instead rely on a new AI dating assistant called ‘Bee’ for matchmaking, profile optimization, and more.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-4" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-4" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Nicolas D.</strong> in Quebec:</p><p>For months, Claude has been my personal coach — tracking my habits, building my workouts, adjusting my plans. Every Sunday, I feed Claude a log of the past week — sessions, wellbeing, and soreness — and it generates next week&#39;s program.</p><p>Then it hit me: my habits are tied to long-term goals. So why not manage them like projects?</p><p>I&#39;ve worked in project management for years. I built a Gantt chart linked directly to my habit-tracking software. The tracker now acts as a time-punch system — every session logged becomes a task completed on the timeline. I&#39;m running my life&#39;s projects the way I run work projects. Best decision I&#39;ve made for staying consistent.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-4" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-4" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/the-enterprise-shift-openai-saw-coming?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">The enterprise shift OpenAI saw coming</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/venmo-finally-kills-its-most-criticized-feature?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Venmo kills its most criticized feature</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meet-unitree-giant-new-mech?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Meet Unitree’s giant new mech</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Automate marketing assets with Image</a><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">s 2.0</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr>',378)])])}const c=t(o,[["render",i]]);export{h as __pageData,c as default};
